// External resources from platform.cpp (declared later in unity build)
extern IDWriteTextFormat* g_text_format_hint;    // 9pt for metadata
extern IDWriteTextFormat* g_text_format_badge;   // For HEAD badge
extern ID2D1Factory* g_d2d_factory;              // For path geometry creation

// Forward declaration - defined in platform.cpp
static void format_relative_time(int64_t timestamp, wchar_t* buffer, size_t buffer_size);
static void sha_raw_to_hex(const uint8_t* sha, char* hex);

// Index entry pointing to a single commit row with precomputed position
struct CommitRowEntry {
    size_t commit_index;     // Index into GitHistory.commits
    float y_offset;          // Absolute Y position from content top
};

// Flat index for O(1) visible range calculation (fixed-height rows)
struct CommitRowIndex {
    CommitRowEntry* entries = nullptr;   // Flat array (allocated via malloc)
    size_t count = 0;                    // Total commit count
    size_t capacity = 0;                 // Allocated capacity
    float total_height = 0.0f;           // Total content height
    float row_height = 0.0f;             // Fixed height per row

    void build_from_history(const GitHistory* history, float rh) {
        row_height = rh;

        // Count total commits
        size_t total = history ? history->commit_count : 0;

        // Ensure capacity
        if (total > capacity) {
            void* mem = malloc(total * sizeof(CommitRowEntry));
            if (!mem) {
                // Allocation failed - clear state and return
                count = 0;
                total_height = 0.0f;
                return;
            }
            if (entries) free(entries);
            entries = static_cast<CommitRowEntry*>(mem);
            capacity = total;
        }

        // Build flat index with precomputed Y positions
        count = 0;
        float y = 0.0f;

        for (size_t i = 0; i < total; i++) {
            entries[count].commit_index = i;
            entries[count].y_offset = y;
            count++;
            y += row_height;
        }

        total_height = y;
    }

    // Build index from filtered commit indices
    void build_from_filter(const int* filter_indices, size_t filter_count, float rh) {
        row_height = rh;

        // Ensure capacity
        if (filter_count > capacity) {
            void* mem = malloc(filter_count * sizeof(CommitRowEntry));
            if (!mem) {
                count = 0;
                total_height = 0.0f;
                return;
            }
            if (entries) free(entries);
            entries = static_cast<CommitRowEntry*>(mem);
            capacity = filter_count;
        }

        // Build index from filtered commits
        count = 0;
        float y = 0.0f;

        for (size_t i = 0; i < filter_count; i++) {
            entries[count].commit_index = static_cast<size_t>(filter_indices[i]);
            entries[count].y_offset = y;
            count++;
            y += row_height;
        }

        total_height = y;
    }

    void clear() {
        count = 0;
        total_height = 0.0f;
    }

    void destroy() {
        if (entries) {
            free(entries);
            entries = nullptr;
        }
        capacity = 0;
        count = 0;
        total_height = 0.0f;
    }

    // O(1) direct calculation since all rows are fixed height
    size_t first_visible_index(float scroll_y) const {
        if (count == 0 || row_height <= 0) return 0;
        int64_t idx = static_cast<int64_t>(scroll_y / row_height);
        if (idx < 0) return 0;
        if (static_cast<size_t>(idx) >= count) return count > 0 ? count - 1 : 0;
        return static_cast<size_t>(idx);
    }

    // Calculate how many rows fit in viewport
    size_t rows_in_viewport(float viewport_height) const {
        if (row_height <= 0) return 0;
        return static_cast<size_t>(viewport_height / row_height) + 2;  // +2 for partial rows
    }
};

// Individual commit row widget with text layout caching
struct CommitRowWidget : Widget {
    // Data binding (set when recycled from pool)
    const CommitMeta* meta = nullptr;
    const GraphNode* node = nullptr;
    const GitHistory* history = nullptr;   // For accessing message/author buffers
    size_t commit_index = 0;
    int pool_index = -1;                   // Index in pool for release

    // State (set by parent list widget)
    bool is_selected = false;
    bool is_hovered = false;

    // Cached text layouts (released on unbind)
    IDWriteTextLayout* layout_message = nullptr;
    IDWriteTextLayout* layout_metadata = nullptr;

    // Cache invalidation tracking
    float cached_width = 0.0f;
    bool cache_valid = false;

    // Cached graph geometries (released on unbind)
    ID2D1PathGeometry* cached_parent1_curve = nullptr;
    ID2D1PathGeometry* cached_parent2_curve = nullptr;

    // Wide string buffers for text conversion
    wchar_t message_wide[256];
    wchar_t metadata_wide[256];

    CommitRowWidget() : Widget() {
        debug_name = "CommitRowWidget";
        message_wide[0] = L'\0';
        metadata_wide[0] = L'\0';
    }

    // Bind to a commit (called when recycling from pool)
    void bind(const GitHistory* h, size_t idx, int pidx) {
        if (!h || idx >= h->commit_count) {
            unbind();
            return;
        }

        history = h;
        commit_index = idx;
        meta = &h->commits[idx];
        node = &h->graph[idx];
        pool_index = pidx;
        cache_valid = false;  // Invalidate cache when binding new data

        // Release cached graph geometry — it's tied to the old commit's
        // parent layout and would render stale curves for the new commit.
        if (cached_parent1_curve) {
            cached_parent1_curve->Release();
            cached_parent1_curve = nullptr;
        }
        if (cached_parent2_curve) {
            cached_parent2_curve->Release();
            cached_parent2_curve = nullptr;
        }

        // Pre-convert message to wide string
        const char* message = git_history_get_message(h, idx);
        if (message) {
            int result = MultiByteToWideChar(CP_UTF8, 0, message, -1, message_wide, 256);
            if (result == 0 && GetLastError() == ERROR_INSUFFICIENT_BUFFER) {
                // Message too long - truncate at safe UTF-8 boundary
                size_t max_bytes = 250;
                size_t len = strlen(message);
                if (len > max_bytes) {
                    // Back up to avoid splitting multi-byte UTF-8 sequences
                    while (max_bytes > 0 && (message[max_bytes] & 0xC0) == 0x80) {
                        max_bytes--;
                    }
                } else {
                    max_bytes = len;
                }
                result = MultiByteToWideChar(CP_UTF8, 0, message, static_cast<int>(max_bytes), message_wide, 255);
                message_wide[result > 0 ? result : 0] = L'\0';
            } else if (result == 0) {
                message_wide[0] = L'\0';
            }
        } else {
            wcscpy_s(message_wide, L"(no message)");
        }

        // Pre-convert metadata to wide string: SHA, author, time
        const char* author = git_history_get_author(h, idx);
        char sha_hex[Git::SHA1_HEX_SIZE + 1];
        sha_raw_to_hex(meta->sha, sha_hex);
        char sha_short[8];
        memcpy(sha_short, sha_hex, 7);
        sha_short[7] = '\0';

        wchar_t author_wide[64];
        if (author) {
            int result = MultiByteToWideChar(CP_UTF8, 0, author, -1, author_wide, 64);
            if (result == 0) wcscpy_s(author_wide, L"Unknown");
        } else {
            wcscpy_s(author_wide, L"Unknown");
        }

        wchar_t time_str[32];
        format_relative_time(meta->timestamp, time_str, 32);

        swprintf_s(metadata_wide, L"%hs  %s  %s", sha_short, author_wide, time_str);
    }

    // Unbind and release cached layouts
    void unbind() {
        meta = nullptr;
        node = nullptr;
        history = nullptr;
        commit_index = 0;

        if (layout_message) {
            layout_message->Release();
            layout_message = nullptr;
        }
        if (layout_metadata) {
            layout_metadata->Release();
            layout_metadata = nullptr;
        }

        // Release cached geometries
        if (cached_parent1_curve) {
            cached_parent1_curve->Release();
            cached_parent1_curve = nullptr;
        }
        if (cached_parent2_curve) {
            cached_parent2_curve->Release();
            cached_parent2_curve = nullptr;
        }

        cache_valid = false;
        cached_width = 0.0f;
        is_selected = false;
        is_hovered = false;
    }

    // Create text layouts if needed (lazy creation)
    void ensure_layouts(float available_width) {
        if (!meta) return;

        // Check if we need to recreate due to width change
        constexpr float WIDTH_EPSILON = 1.0f;
        bool width_changed = (cached_width - available_width > WIDTH_EPSILON) ||
                            (available_width - cached_width > WIDTH_EPSILON);

        if (cache_valid && !width_changed) return;

        // Release old layouts
        if (layout_message) { layout_message->Release(); layout_message = nullptr; }
        if (layout_metadata) { layout_metadata->Release(); layout_metadata = nullptr; }

        if (g_dwrite_factory && g_text_format_body) {
            // Message layout (line 1)
            if (message_wide[0]) {
                g_dwrite_factory->CreateTextLayout(
                    message_wide, static_cast<UINT32>(wcslen(message_wide)),
                    g_text_format_body, available_width, 16.0f, &layout_message);
                if (layout_message) {
                    layout_message->SetWordWrapping(DWRITE_WORD_WRAPPING_NO_WRAP);
                    // Add trimming with ellipsis
                    DWRITE_TRIMMING trimming = { DWRITE_TRIMMING_GRANULARITY_CHARACTER, 0, 0 };
                    IDWriteInlineObject* ellipsis = nullptr;
                    g_dwrite_factory->CreateEllipsisTrimmingSign(layout_message, &ellipsis);
                    layout_message->SetTrimming(&trimming, ellipsis);
                    if (ellipsis) ellipsis->Release();
                }
            }

            // Metadata layout (line 2)
            if (metadata_wide[0] && g_text_format_hint) {
                g_dwrite_factory->CreateTextLayout(
                    metadata_wide, static_cast<UINT32>(wcslen(metadata_wide)),
                    g_text_format_hint, available_width, 12.0f, &layout_metadata);
                if (layout_metadata) {
                    layout_metadata->SetWordWrapping(DWRITE_WORD_WRAPPING_NO_WRAP);
                }
            }
        }

        cached_width = available_width;
        cache_valid = true;
    }

    // Render graph cell (lanes, curves, node)
    void render_graph_cell(RenderContext& ctx, float left, float top) {
        if (!node || !meta) return;

        float row_height = CommitHistory::ROW_HEIGHT;
        float lane_width = CommitHistory::GRAPH_LANE_WIDTH;
        float lane_offset = CommitHistory::GRAPH_LANE_OFFSET;
        float line_width = CommitHistory::GRAPH_LINE_WIDTH;
        float node_radius = CommitHistory::GRAPH_NODE_RADIUS;

        // Calculate center Y of this row
        float cy = top + row_height / 2.0f;

        // Helper to get lane X position
        auto lane_x = [=](int lane) -> float {
            return left + lane_offset + lane * lane_width;
        };

        // Get this commit's lane and color
        int my_lane = node->lane;
        uint32_t my_color = CommitHistory::GRAPH_COLORS[node->color_index % CommitHistory::GRAPH_COLOR_COUNT];

        // Get active lanes bitmask
        uint32_t active_mask = node->active_lane_mask_low |
                               (static_cast<uint32_t>(node->active_lane_mask_mid) << 8) |
                               (static_cast<uint32_t>(node->active_lane_mask_high) << 16) |
                               (static_cast<uint32_t>(node->active_lane_mask_top) << 24);

        // Draw vertical lines for each active lane
        for (int lane = 0; lane < static_cast<int>(Git::MAX_LANES); lane++) {
            if (!(active_mask & (1u << lane))) continue;
            if (lane == my_lane) continue;  // We'll draw this lane's connection to node

            // Get color for this lane
            uint32_t lane_color = CommitHistory::GRAPH_COLORS[lane % CommitHistory::GRAPH_COLOR_COUNT];
            ctx.draw_line(lane_x(lane), top, lane_x(lane), top + row_height, lane_color, line_width);
        }

        // Draw vertical line through this commit's lane
        // Line above node
        if (!(node->flags & GraphNodeFlags::LANE_START)) {
            ctx.draw_line(lane_x(my_lane), top, lane_x(my_lane), cy - node_radius, my_color, line_width);
        }

        // Line below node
        if (!(node->flags & GraphNodeFlags::LANE_END)) {
            ctx.draw_line(lane_x(my_lane), cy + node_radius, lane_x(my_lane), top + row_height, my_color, line_width);
        }

        // Draw merge lines to parent lanes if they differ (first parent)
        if (node->parent1.target_lane >= 0 && node->parent1.target_lane != my_lane) {
            // Create cached geometry if needed (using local coordinates with left=0, top=0)
            if (!cached_parent1_curve && g_d2d_factory) {
                // Local coordinates: lane positions relative to x=0
                float local_node_x = lane_offset + my_lane * lane_width;
                float local_parent_x = lane_offset + node->parent1.target_lane * lane_width;
                float local_cy = row_height / 2.0f;

                g_d2d_factory->CreatePathGeometry(&cached_parent1_curve);
                if (cached_parent1_curve) {
                    ID2D1GeometrySink* sink = nullptr;
                    if (SUCCEEDED(cached_parent1_curve->Open(&sink))) {
                        sink->BeginFigure(D2D1::Point2F(local_node_x, local_cy + node_radius), D2D1_FIGURE_BEGIN_HOLLOW);
                        sink->AddBezier(D2D1::BezierSegment(
                            D2D1::Point2F(local_node_x, local_cy + row_height * 0.4f),
                            D2D1::Point2F(local_parent_x, row_height * 0.6f),
                            D2D1::Point2F(local_parent_x, row_height)
                        ));
                        sink->EndFigure(D2D1_FIGURE_END_OPEN);
                        sink->Close();
                        sink->Release();
                    } else {
                        cached_parent1_curve->Release();
                        cached_parent1_curve = nullptr;
                    }
                }
            }

            // Draw using cached geometry with transform
            if (cached_parent1_curve) {
                D2D1_MATRIX_3X2_F old_transform;
                ctx.target->GetTransform(&old_transform);
                ctx.target->SetTransform(old_transform * D2D1::Matrix3x2F::Translation(left, top));
                ctx.brush->SetColor(color_from_argb(my_color));
                ctx.target->DrawGeometry(cached_parent1_curve, ctx.brush, line_width);
                ctx.target->SetTransform(old_transform);
            }
        }

        // Draw second parent merge line (for merge commits)
        if (node->parent2.target_lane >= 0 && node->parent2.target_lane != my_lane) {
            // Create cached geometry if needed (using local coordinates with left=0, top=0)
            if (!cached_parent2_curve && g_d2d_factory) {
                // Local coordinates: lane positions relative to x=0
                float local_node_x = lane_offset + my_lane * lane_width;
                float local_parent_x = lane_offset + node->parent2.target_lane * lane_width;
                float local_cy = row_height / 2.0f;

                g_d2d_factory->CreatePathGeometry(&cached_parent2_curve);
                if (cached_parent2_curve) {
                    ID2D1GeometrySink* sink = nullptr;
                    if (SUCCEEDED(cached_parent2_curve->Open(&sink))) {
                        sink->BeginFigure(D2D1::Point2F(local_node_x, local_cy), D2D1_FIGURE_BEGIN_HOLLOW);
                        sink->AddBezier(D2D1::BezierSegment(
                            D2D1::Point2F(local_node_x, local_cy + row_height * 0.3f),
                            D2D1::Point2F(local_parent_x, row_height * 0.7f),
                            D2D1::Point2F(local_parent_x, row_height)
                        ));
                        sink->EndFigure(D2D1_FIGURE_END_OPEN);
                        sink->Close();
                        sink->Release();
                    } else {
                        cached_parent2_curve->Release();
                        cached_parent2_curve = nullptr;
                    }
                }
            }

            // Draw using cached geometry with transform
            if (cached_parent2_curve) {
                D2D1_MATRIX_3X2_F old_transform;
                ctx.target->GetTransform(&old_transform);
                ctx.target->SetTransform(old_transform * D2D1::Matrix3x2F::Translation(left, top));
                ctx.brush->SetColor(color_from_argb(my_color));
                ctx.target->DrawGeometry(cached_parent2_curve, ctx.brush, line_width);
                ctx.target->SetTransform(old_transform);
            }
        }

        // Draw commit node
        D2D1_ELLIPSE node_ellipse = D2D1::Ellipse(D2D1::Point2F(lane_x(my_lane), cy), node_radius, node_radius);
        ctx.brush->SetColor(color_from_argb(my_color));
        ctx.target->FillEllipse(node_ellipse, ctx.brush);

        // Draw HEAD ring if this is HEAD
        if (meta->flags & CommitMetaFlags::IS_HEAD) {
            ctx.brush->SetColor(color_from_argb(Theme::TEXT_PRIMARY));
            float head_radius = CommitHistory::GRAPH_HEAD_RADIUS;
            D2D1_ELLIPSE head_ellipse = D2D1::Ellipse(D2D1::Point2F(lane_x(my_lane), cy), head_radius, head_radius);
            ctx.target->DrawEllipse(head_ellipse, ctx.brush, 2.0f);
        }
    }

    void render(RenderContext& ctx) override {
        if (!meta || !(flags & WidgetFlags::Visible)) return;

        float x = rect.x;
        float y = rect.y;
        float w = rect.width;
        float h = rect.height;
        float graph_width = CommitHistory::GRAPH_WIDTH;

        // Draw selection/hover background
        if (is_selected) {
            D2D1_RECT_F bg = D2D1::RectF(x, y, x + w, y + h);
            ctx.brush->SetColor(color_from_argb(Theme::ACCENT));
            ctx.brush->SetOpacity(0.15f);
            ctx.target->FillRectangle(bg, ctx.brush);
            ctx.brush->SetOpacity(1.0f);

            // Selection border on left
            D2D1_RECT_F border = D2D1::RectF(x, y, x + 3.0f, y + h);
            ctx.fill_rect(border, Theme::SELECTION_BORDER);
        } else if (is_hovered) {
            D2D1_RECT_F bg = D2D1::RectF(x, y, x + w, y + h);
            ctx.fill_rect(bg, Theme::BG_HOVER);
        }

        // Draw graph
        render_graph_cell(ctx, x, y);

        // Text layout positions
        float text_left = x + graph_width + CommitHistory::MESSAGE_PADDING_LEFT;
        float line1_y = y + CommitHistory::LINE1_Y_OFFSET;
        float line2_y = y + CommitHistory::LINE2_Y_OFFSET;
        float message_x = text_left;

        // Draw HEAD badge if applicable
        if (meta->flags & CommitMetaFlags::IS_HEAD) {
            float badge_y = line1_y;
            D2D1_ROUNDED_RECT badge_rect = D2D1::RoundedRect(
                D2D1::RectF(text_left, badge_y,
                            text_left + CommitHistory::HEAD_BADGE_WIDTH,
                            badge_y + CommitHistory::HEAD_BADGE_HEIGHT),
                CommitHistory::HEAD_BADGE_RADIUS, CommitHistory::HEAD_BADGE_RADIUS
            );
            ctx.brush->SetColor(color_from_argb(Theme::ACCENT));
            ctx.target->FillRoundedRectangle(badge_rect, ctx.brush);

            // HEAD text
            if (g_text_format_badge) {
                ctx.brush->SetColor(color_from_argb(Theme::TEXT_PRIMARY));
                ctx.target->DrawText(
                    L"HEAD", 4, g_text_format_badge,
                    D2D1::RectF(text_left + 4.0f, badge_y,
                                text_left + CommitHistory::HEAD_BADGE_WIDTH,
                                badge_y + CommitHistory::HEAD_BADGE_HEIGHT),
                    ctx.brush
                );
            }

            message_x += CommitHistory::HEAD_BADGE_WIDTH + CommitHistory::DECORATION_SPACING;
        }

        // Draw commit message (line 1)
        if (layout_message) {
            ctx.brush->SetColor(color_from_argb(Theme::TEXT_PRIMARY));
            ctx.target->DrawTextLayout(D2D1::Point2F(message_x, line1_y), layout_message, ctx.brush);
        }

        // Draw metadata (line 2)
        if (layout_metadata) {
            ctx.brush->SetColor(color_from_argb(Theme::TEXT_SECONDARY));
            ctx.target->DrawTextLayout(D2D1::Point2F(text_left, line2_y), layout_metadata, ctx.brush);
        }
    }
};

// Pool manager for recycling CommitRowWidget instances
// Uses free list for O(1) acquire/release instead of O(n) scan
struct CommitRowPool {
    static constexpr size_t POOL_SIZE = 100;  // Enough for viewport + overscan
    static constexpr int FREE_LIST_END = -1;

    CommitRowWidget* widgets[POOL_SIZE] = {};  // Pre-allocated in arena
    int next_free[POOL_SIZE] = {};             // Free list links (-1 = end, -2 = in use)
    int free_head = FREE_LIST_END;             // Head of free list
    size_t allocated_count = 0;                // How many have been created
    size_t in_use_count = 0;                   // How many are currently bound

    // Initialize pool by pre-allocating all widgets
    void init(WidgetArena& arena) {
        free_head = FREE_LIST_END;
        for (size_t i = 0; i < POOL_SIZE; i++) {
            widgets[i] = arena.create<CommitRowWidget>();
            if (widgets[i]) {
                widgets[i]->pool_index = static_cast<int>(i);
                // Build free list in reverse order so index 0 is acquired first
                next_free[i] = free_head;
                free_head = static_cast<int>(i);
                allocated_count++;
            }
        }
    }

    // Acquire an unused widget from the pool - O(1)
    CommitRowWidget* acquire() {
        if (free_head == FREE_LIST_END) return nullptr;  // Pool exhausted

        int idx = free_head;
        free_head = next_free[idx];
        next_free[idx] = -2;  // Mark as in use
        in_use_count++;
        return widgets[idx];
    }

    // Release a widget back to the pool - O(1)
    void release(CommitRowWidget* w) {
        if (!w || w->pool_index < 0 || static_cast<size_t>(w->pool_index) >= POOL_SIZE) return;

        int idx = w->pool_index;
        if (widgets[idx] == w && next_free[idx] == -2) {  // Currently in use
            w->unbind();
            next_free[idx] = free_head;
            free_head = idx;
            in_use_count--;
        }
    }

    // Release all widgets (for history change)
    void release_all() {
        free_head = FREE_LIST_END;
        for (size_t i = 0; i < allocated_count; i++) {
            if (next_free[i] == -2 && widgets[i]) {  // Was in use
                widgets[i]->unbind();
            }
            // Rebuild free list
            next_free[i] = free_head;
            free_head = static_cast<int>(i);
        }
        in_use_count = 0;
    }

    // Count of currently in-use widgets - O(1)
    size_t active_count() const {
        return in_use_count;
    }
};

// Virtualized commit history list widget
struct CommitHistoryListWidget : Widget {
    // Data
    const GitHistory* history = nullptr;
    CommitRowIndex row_index;

    // Pool for row widgets
    CommitRowPool row_pool;
    bool pool_initialized = false;

    // Layout constants
    static constexpr float ROW_HEIGHT = CommitHistory::ROW_HEIGHT;
    static constexpr int OVERSCAN_ROWS = 10;  // Rows above/below viewport

    // Viewport (from ScrollContainer via on_viewport_changed)
    float viewport_top = 0.0f;
    float viewport_bottom = 0.0f;

    // Currently bound range (row indices)
    size_t bound_first = 0;
    size_t bound_last = 0;

    // Selection state (synced with platform.cpp state)
    int selected_index = -1;
    int hovered_index = -1;

    // Filter state
    bool filter_active = false;  // True when showing filtered results

    // Active widgets for current viewport (maps row index -> widget)
    static constexpr size_t MAX_ACTIVE = CommitRowPool::POOL_SIZE;
    struct ActiveBinding {
        size_t row_index;
        CommitRowWidget* widget;
    };
    ActiveBinding active_widgets[MAX_ACTIVE] = {};
    size_t active_widget_count = 0;

    // Callback for selection changes
    void (*on_selection_changed)(CommitHistoryListWidget* list, int index, void* user_data) = nullptr;
    void* user_data = nullptr;

    // Callback for context menu (right-click)
    void (*on_context_menu)(CommitHistoryListWidget* list, int row_index,
                            float screen_x, float screen_y, void* user_data) = nullptr;

    // Callback for requesting scroll position change (handled by parent panel)
    void (*on_scroll_request)(CommitHistoryListWidget* list, float scroll_y, void* user_data) = nullptr;
    void* scroll_request_user_data = nullptr;

    CommitHistoryListWidget() : Widget() {
        debug_name = "CommitHistoryListWidget";
        flags |= WidgetFlags::RendersOwnChildren;  // We handle child rendering with culling
        flags |= WidgetFlags::Focusable;
        row_index.row_height = ROW_HEIGHT;
    }

    // Initialize the pool (called once)
    void init_pool(WidgetArena& arena) {
        if (!pool_initialized) {
            row_pool.init(arena);
            pool_initialized = true;
        }
    }

    // Set the history to display
    void set_history(const GitHistory* h) {
        // Release all active widgets
        release_all_active();

        history = h;

        // Rebuild index
        row_index.build_from_history(h, ROW_HEIGHT);
        filter_active = false;  // New history means no filter

        // Reset viewport state
        bound_first = 0;
        bound_last = 0;
        selected_index = -1;
        hovered_index = -1;

        // Update preferred size
        preferred_height = row_index.total_height;
        preferred_width = 400.0f;  // Minimum width

        set_dirty();
    }

    // Rebuild index from filtered commit indices
    void rebuild_from_filter(const int* filter_indices, size_t filter_count) {
        // Release all active widgets
        release_all_active();

        // Rebuild index from filter
        row_index.build_from_filter(filter_indices, filter_count, ROW_HEIGHT);
        filter_active = true;

        // Reset viewport state
        bound_first = 0;
        bound_last = 0;
        // Don't reset selected_index - preserve selection if still valid
        hovered_index = -1;

        // Update preferred size (minimum height for "no results" message)
        preferred_height = row_index.total_height > 0 ? row_index.total_height : 48.0f;

        set_dirty();
    }

    // Rebuild index from full history (clear filter)
    void rebuild_from_history() {
        // Release all active widgets
        release_all_active();

        // Rebuild index from full history
        row_index.build_from_history(history, ROW_HEIGHT);
        filter_active = false;

        // Reset viewport state
        bound_first = 0;
        bound_last = 0;
        // Don't reset selected_index - preserve selection
        hovered_index = -1;

        // Update preferred size
        preferred_height = row_index.total_height;

        set_dirty();
    }

    // Called by ScrollContainer when viewport changes
    void on_viewport_changed(float vp_top, float vp_bottom) override {
        viewport_top = vp_top;
        viewport_bottom = vp_bottom;
        update_visible_range();
    }

    // Release all active widget bindings
    void release_all_active() {
        for (size_t i = 0; i < active_widget_count; i++) {
            if (active_widgets[i].widget) {
                row_pool.release(active_widgets[i].widget);
            }
        }
        active_widget_count = 0;
    }

    // Find if we have an active widget for a given row index
    CommitRowWidget* find_active_widget(size_t row_idx) {
        for (size_t i = 0; i < active_widget_count; i++) {
            if (active_widgets[i].row_index == row_idx) {
                return active_widgets[i].widget;
            }
        }
        return nullptr;
    }

    // Remove an active binding by row index
    void remove_active_binding(size_t row_idx) {
        for (size_t i = 0; i < active_widget_count; i++) {
            if (active_widgets[i].row_index == row_idx) {
                if (active_widgets[i].widget) {
                    row_pool.release(active_widgets[i].widget);
                }
                // Move last element to fill gap
                if (i < active_widget_count - 1) {
                    active_widgets[i] = active_widgets[active_widget_count - 1];
                }
                active_widget_count--;
                return;
            }
        }
    }

    // Add an active binding
    void add_active_binding(size_t row_idx, CommitRowWidget* widget) {
        if (active_widget_count < MAX_ACTIVE) {
            active_widgets[active_widget_count].row_index = row_idx;
            active_widgets[active_widget_count].widget = widget;
            active_widget_count++;
        }
    }

    // Update visible range and recycle widgets
    void update_visible_range() {
        if (row_index.count == 0) {
            release_all_active();
            return;
        }

        // Skip if viewport hasn't been set yet
        if (viewport_bottom <= viewport_top) {
            return;
        }

        // Calculate scroll offset from viewport position
        float scroll_offset = viewport_top - rect.y;
        if (scroll_offset < 0) scroll_offset = 0;

        // Calculate visible range in content-local coordinates
        float viewport_height = viewport_bottom - viewport_top;
        float visible_bottom = scroll_offset + viewport_height;

        // Clamp to valid range
        if (visible_bottom > row_index.total_height) visible_bottom = row_index.total_height;

        // Calculate first and last visible indices
        size_t new_first = row_index.first_visible_index(scroll_offset);
        size_t viewport_rows = row_index.rows_in_viewport(visible_bottom - scroll_offset);
        size_t new_last = new_first + viewport_rows;

        // Add overscan buffer
        if (new_first > static_cast<size_t>(OVERSCAN_ROWS)) {
            new_first -= OVERSCAN_ROWS;
        } else {
            new_first = 0;
        }
        new_last += OVERSCAN_ROWS;
        if (new_last > row_index.count) {
            new_last = row_index.count;
        }

        // Calculate layout values needed for positioning
        float text_area_width = rect.width - CommitHistory::GRAPH_WIDTH - CommitHistory::MESSAGE_PADDING_LEFT
                               - CommitHistory::SCROLLBAR_WIDTH - 10.0f;
        if (text_area_width < 0) text_area_width = 100.0f;

        // Always update positions and state of existing widgets
        for (size_t i = 0; i < active_widget_count; i++) {
            size_t row_idx = active_widgets[i].row_index;
            CommitRowWidget* widget = active_widgets[i].widget;
            if (!widget || row_idx >= row_index.count) continue;

            CommitRowEntry* entry = &row_index.entries[row_idx];
            widget->rect.x = rect.x;
            widget->rect.y = rect.y + entry->y_offset;
            widget->rect.width = rect.width;

            // Update selection/hover state
            widget->is_selected = (static_cast<int>(row_idx) == selected_index);
            widget->is_hovered = (static_cast<int>(row_idx) == hovered_index);

            // Ensure layouts are valid for current width (handles resize)
            widget->ensure_layouts(text_area_width);
        }

        // If range hasn't changed, we're done after updating positions
        if (new_first == bound_first && new_last == bound_last) {
            return;
        }

        // Release widgets outside new range
        for (size_t i = active_widget_count; i > 0; ) {
            i--;
            size_t row_idx = active_widgets[i].row_index;
            if (row_idx < new_first || row_idx >= new_last) {
                if (active_widgets[i].widget) {
                    row_pool.release(active_widgets[i].widget);
                }
                // Move last to fill gap
                if (i < active_widget_count - 1) {
                    active_widgets[i] = active_widgets[active_widget_count - 1];
                }
                active_widget_count--;
            }
        }

        // Acquire widgets for new rows in range
        size_t actual_last = new_first;  // Track actual progress for pool exhaustion case
        for (size_t idx = new_first; idx < new_last; idx++) {
            // Check if we already have a widget for this row
            if (find_active_widget(idx)) {
                actual_last = idx + 1;
                continue;
            }

            // Get row entry
            CommitRowEntry* entry = &row_index.entries[idx];

            // Acquire a widget from pool
            CommitRowWidget* widget = row_pool.acquire();
            if (!widget) {
                // Pool exhausted - don't update bound_last past what we achieved
                break;
            }

            // Bind widget to commit
            widget->bind(history, entry->commit_index, widget->pool_index);

            // Position widget
            widget->rect.x = rect.x;
            widget->rect.y = rect.y + entry->y_offset;
            widget->rect.width = rect.width;
            widget->rect.height = ROW_HEIGHT;

            // Update selection/hover state
            widget->is_selected = (static_cast<int>(idx) == selected_index);
            widget->is_hovered = (static_cast<int>(idx) == hovered_index);

            // Ensure layouts are created
            widget->ensure_layouts(text_area_width);

            // Add to active list
            add_active_binding(idx, widget);
            actual_last = idx + 1;
        }

        bound_first = new_first;
        bound_last = actual_last;  // Use actual progress, not target

        set_dirty();
    }

    void measure(const LayoutConstraints& c) override {
        (void)c;
        preferred_height = row_index.total_height;
        preferred_width = 400.0f;
    }

    void render(RenderContext& ctx) override {
        if (!history || !(flags & WidgetFlags::Visible)) return;

        // Show "no results" message when filter is active but empty
        if (filter_active && row_index.count == 0) {
            D2D1_RECT_F text_rect = D2D1::RectF(
                rect.x + Theme::PADDING,
                rect.y + Theme::PADDING,
                rect.x + rect.width - Theme::PADDING,
                rect.y + 48.0f
            );
            if (g_text_format_body) {
                ctx.draw_text(L"No matching commits", 19, g_text_format_body, text_rect, Theme::TEXT_MUTED);
            }
            return;
        }

        // Render all active widgets (they're already culled to viewport)
        for (size_t i = 0; i < active_widget_count; i++) {
            CommitRowWidget* widget = active_widgets[i].widget;
            if (widget) {
                widget->render(ctx);
            }
        }
    }

    // Set selection and update widget states
    void set_selection(int index) {
        if (index == selected_index) return;

        int old_index = selected_index;
        selected_index = index;

        // Update widget states
        for (size_t i = 0; i < active_widget_count; i++) {
            CommitRowWidget* widget = active_widgets[i].widget;
            if (!widget) continue;

            int row_idx = static_cast<int>(active_widgets[i].row_index);
            widget->is_selected = (row_idx == selected_index);
            if (row_idx == old_index || row_idx == selected_index) {
                widget->set_dirty();
            }
        }

        // Notify callback
        if (on_selection_changed) {
            on_selection_changed(this, selected_index, user_data);
        }

        set_dirty();
    }

    // Set hover and update widget states
    void set_hover(int index) {
        if (index == hovered_index) return;

        int old_index = hovered_index;
        hovered_index = index;

        // Update widget states
        for (size_t i = 0; i < active_widget_count; i++) {
            CommitRowWidget* widget = active_widgets[i].widget;
            if (!widget) continue;

            int row_idx = static_cast<int>(active_widgets[i].row_index);
            widget->is_hovered = (row_idx == hovered_index);
            if (row_idx == old_index || row_idx == hovered_index) {
                widget->set_dirty();
            }
        }

        set_dirty();
    }

    // Calculate row index from Y coordinate (relative to widget)
    int row_from_y(float y) const {
        if (row_index.count == 0 || ROW_HEIGHT <= 0) return -1;
        int idx = static_cast<int>(y / ROW_HEIGHT);
        if (idx < 0) return -1;
        if (static_cast<size_t>(idx) >= row_index.count) return -1;
        return idx;
    }

    bool on_mouse_move(float x, float y) override {
        (void)x;
        // y is already in content-space (scroll-adjusted by ScrollContainer)
        int row = row_from_y(y);
        set_hover(row);
        return true;
    }

    bool on_mouse_leave() override {
        set_hover(-1);
        return true;
    }

    bool on_mouse_down(float x, float y, int button) override {
        // y is already in content-space (scroll-adjusted by ScrollContainer)
        int row = row_from_y(y);

        // Right-click: show context menu
        if (button == 1) {
            if (row >= 0 && on_context_menu) {
                // Select the row on right-click
                set_selection(row);
                // Convert to screen coordinates
                POINT pt = { static_cast<LONG>(rect.x + x), static_cast<LONG>(rect.y + y) };
                ClientToScreen(g_main_window, &pt);
                on_context_menu(this, row, static_cast<float>(pt.x), static_cast<float>(pt.y), user_data);
            }
            return true;
        }

        if (button != 0) return false;  // Left button only for other logic

        if (row >= 0) {
            set_selection(row);
            return true;
        }
        return false;
    }

    // Request scroll position to make a row visible
    void ensure_row_visible(int row) {
        if (row < 0 || static_cast<size_t>(row) >= row_index.count) return;

        float row_top = row * ROW_HEIGHT;
        float row_bottom = row_top + ROW_HEIGHT;
        float viewport_height = viewport_bottom - viewport_top;
        float scroll_y = viewport_top - rect.y;  // Current scroll offset

        float new_scroll = scroll_y;
        if (row_top < scroll_y) {
            // Row is above viewport - scroll up
            new_scroll = row_top;
        } else if (row_bottom > scroll_y + viewport_height) {
            // Row is below viewport - scroll down
            new_scroll = row_bottom - viewport_height;
        }

        if (new_scroll != scroll_y && on_scroll_request) {
            on_scroll_request(this, new_scroll, scroll_request_user_data);
        }
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;
        if (row_index.count == 0) return false;

        int row_count = static_cast<int>(row_index.count);
        int new_index = selected_index;

        if (vk == VK_UP) {
            if (selected_index <= 0) {
                new_index = 0;
            } else {
                new_index = selected_index - 1;
            }
        } else if (vk == VK_DOWN) {
            if (selected_index < 0) {
                new_index = 0;
            } else if (selected_index < row_count - 1) {
                new_index = selected_index + 1;
            }
        } else if (vk == VK_HOME) {
            new_index = 0;
        } else if (vk == VK_END) {
            new_index = row_count - 1;
        } else if (vk == VK_PRIOR) {  // Page Up
            float viewport_height = viewport_bottom - viewport_top;
            int page_rows = static_cast<int>(viewport_height / ROW_HEIGHT);
            if (page_rows < 1) page_rows = 1;
            new_index = (selected_index > page_rows) ? selected_index - page_rows : 0;
        } else if (vk == VK_NEXT) {  // Page Down
            float viewport_height = viewport_bottom - viewport_top;
            int page_rows = static_cast<int>(viewport_height / ROW_HEIGHT);
            if (page_rows < 1) page_rows = 1;
            new_index = (selected_index + page_rows < row_count - 1) ? selected_index + page_rows : row_count - 1;
        } else {
            return false;
        }

        if (new_index != selected_index) {
            set_selection(new_index);
            ensure_row_visible(new_index);
        }
        return true;
    }
};

// Header widget for commit history panel ("HISTORY" title bar with search box)
struct CommitHistoryHeaderWidget : Widget {
    size_t commit_count = 0;
    size_t displayed_count = 0;  // When filtered, shows filtered count
    wchar_t count_str[32] = {};
    bool is_filtered = false;

    // Search input child widget
    TextInput* search_input = nullptr;

    // Callback when search query changes
    void (*on_search_changed)(const wchar_t* query, void* user_data) = nullptr;
    void* search_user_data = nullptr;

    CommitHistoryHeaderWidget() : Widget() {
        debug_name = "CommitHistoryHeaderWidget";
        preferred_height = CommitHistory::HEADER_HEIGHT;
    }

    void init(WidgetArena& arena) {
        // Create search input
        search_input = arena.create<TextInput>();
        search_input->placeholder = L"Search commits...";
        search_input->preferred_width = CommitHistory::SEARCH_BOX_WIDTH;
        search_input->preferred_height = CommitHistory::SEARCH_BOX_HEIGHT;
        search_input->corner_radius = CommitHistory::SEARCH_BOX_RADIUS;
        search_input->bg_color = CommitHistory::SEARCH_BOX_BG;
        search_input->border_color = CommitHistory::SEARCH_BOX_BORDER;
        search_input->border_focus = CommitHistory::SEARCH_BOX_FOCUS;
        search_input->padding_left = CommitHistory::SEARCH_BOX_PADDING;
        search_input->padding_right = CommitHistory::SEARCH_BOX_PADDING;
        search_input->padding_top = 4.0f;
        search_input->padding_bottom = 4.0f;

        // Wire up change callback
        search_input->on_change = [](TextInput* input, void* ud) {
            auto* header = static_cast<CommitHistoryHeaderWidget*>(ud);
            if (header->on_search_changed) {
                header->on_search_changed(input->text, header->search_user_data);
            }
        };
        search_input->user_data = this;

        widget_add_child(this, search_input);
    }

    void set_commit_count(size_t count) {
        commit_count = count;
        displayed_count = count;
        is_filtered = false;
        update_count_str();
        set_dirty();
    }

    void set_filtered_count(size_t filtered, size_t total) {
        commit_count = total;
        displayed_count = filtered;
        is_filtered = (filtered != total);
        update_count_str();
        set_dirty();
    }

    void update_count_str() {
        if (displayed_count > 0) {
            if (is_filtered) {
                swprintf_s(count_str, L"%zu/%zu", displayed_count, commit_count);
            } else {
                swprintf_s(count_str, L"%zu", displayed_count);
            }
        } else {
            count_str[0] = L'\0';
        }
    }

    void clear_search() {
        if (search_input) {
            search_input->text[0] = L'\0';
            search_input->text_len = 0;
            search_input->cursor_pos = 0;
            search_input->set_dirty();
        }
    }

    void measure(const LayoutConstraints& c) override {
        (void)c;
        preferred_height = CommitHistory::HEADER_HEIGHT;
        preferred_width = 200.0f;  // Will be stretched by parent
    }

    void layout() override {
        // Position search input on the right side
        if (search_input) {
            float search_x = rect.x + rect.width - CommitHistory::SEARCH_BOX_WIDTH - CommitHistory::SEARCH_BOX_MARGIN;
            float search_y = rect.y + (rect.height - CommitHistory::SEARCH_BOX_HEIGHT) / 2.0f;
            search_input->rect.x = search_x;
            search_input->rect.y = search_y;
            search_input->rect.width = CommitHistory::SEARCH_BOX_WIDTH;
            search_input->rect.height = CommitHistory::SEARCH_BOX_HEIGHT;
        }
    }

    void render(RenderContext& ctx) override {
        if (!(flags & WidgetFlags::Visible)) return;

        float x = rect.x;
        float y = rect.y;
        float w = rect.width;
        float h = rect.height;

        // Background
        D2D1_RECT_F bg = D2D1::RectF(x, y, x + w, y + h);
        ctx.fill_rect(bg, Theme::BG_SECONDARY);

        // Border on top
        D2D1_RECT_F border = D2D1::RectF(x, y, x + w, y + 1.0f);
        ctx.fill_rect(border, Theme::BORDER);

        // Title "HISTORY"
        if (g_text_format_header) {
            ctx.brush->SetColor(color_from_argb(Theme::TEXT_SECONDARY));
            ctx.target->DrawText(
                L"HISTORY", 7, g_text_format_header,
                D2D1::RectF(x + Theme::PADDING, y, x + w, y + h),
                ctx.brush
            );
        }

        // Calculate badge position (left of search box)
        float search_left = x + w - CommitHistory::SEARCH_BOX_WIDTH - CommitHistory::SEARCH_BOX_MARGIN;

        // Commit count badge
        if (count_str[0] && g_text_format_badge) {
            // Measure badge width based on content
            float badge_w = is_filtered ? 60.0f : 40.0f;  // Wider for "123/456" format
            float badge_h = 16.0f;
            float badge_x = search_left - badge_w - 8.0f;
            float badge_y = y + (h - badge_h) / 2.0f;

            D2D1_ROUNDED_RECT badge_rect = D2D1::RoundedRect(
                D2D1::RectF(badge_x, badge_y, badge_x + badge_w, badge_y + badge_h),
                3.0f, 3.0f
            );
            ctx.brush->SetColor(color_from_argb(Theme::BG_TERTIARY));
            ctx.target->FillRoundedRectangle(badge_rect, ctx.brush);

            ctx.brush->SetColor(color_from_argb(Theme::TEXT_SECONDARY));
            ctx.target->DrawText(
                count_str, static_cast<UINT32>(wcslen(count_str)), g_text_format_badge,
                D2D1::RectF(badge_x, badge_y, badge_x + badge_w, badge_y + badge_h),
                ctx.brush
            );
        }

        // Render search input
        if (search_input) {
            search_input->render(ctx);
        }
    }

    bool on_mouse_move(float x, float y) override {
        if (search_input) {
            float abs_x = rect.x + x;
            float abs_y = rect.y + y;
            bool was_hovered = (search_input->flags & WidgetFlags::Hovered) != 0;
            bool is_over = search_input->rect.contains(abs_x, abs_y);

            if (is_over && !was_hovered) {
                search_input->flags |= WidgetFlags::Hovered;
                search_input->on_mouse_enter();
                search_input->set_dirty();
            } else if (!is_over && was_hovered) {
                search_input->flags &= ~WidgetFlags::Hovered;
                search_input->on_mouse_leave();
                search_input->set_dirty();
            }

            if (is_over) {
                float child_x = abs_x - search_input->rect.x;
                float child_y = abs_y - search_input->rect.y;
                return search_input->on_mouse_move(child_x, child_y);
            }
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        // Focus is handled by EventDispatcher - just forward the event
        if (search_input) {
            float abs_x = rect.x + x;
            float abs_y = rect.y + y;
            if (search_input->rect.contains(abs_x, abs_y)) {
                float child_x = abs_x - search_input->rect.x;
                float child_y = abs_y - search_input->rect.y;
                search_input->on_mouse_down(child_x, child_y, button);
                return true;
            }
        }
        return false;
    }

    bool on_mouse_up(float x, float y, int button) override {
        if (search_input) {
            float abs_x = rect.x + x;
            float abs_y = rect.y + y;
            if (search_input->rect.contains(abs_x, abs_y)) {
                float child_x = abs_x - search_input->rect.x;
                float child_y = abs_y - search_input->rect.y;
                return search_input->on_mouse_up(child_x, child_y, button);
            }
        }
        return false;
    }
};

// Main commit history panel widget (header + scrollable list)
struct CommitHistoryPanelWidget : Widget {
    // Child widgets
    CommitHistoryHeaderWidget* header = nullptr;
    ScrollContainer* scroll_container = nullptr;
    CommitHistoryListWidget* list = nullptr;

    // Callback for selection changes
    void (*on_selection_changed)(CommitHistoryPanelWidget* panel, int index, void* user_data) = nullptr;
    void* user_data = nullptr;

    // Callback for search query changes
    void (*on_search_changed)(CommitHistoryPanelWidget* panel, const wchar_t* query, void* user_data) = nullptr;
    void* search_user_data = nullptr;

    CommitHistoryPanelWidget() : Widget() {
        debug_name = "CommitHistoryPanelWidget";
    }

    // Initialize the panel with child widgets
    void init(WidgetArena& arena) {
        // Create header
        header = arena.create<CommitHistoryHeaderWidget>();
        header->init(arena);  // Create search input
        header->width_mode = SizeMode::Fill;
        header->height_mode = SizeMode::Fixed;

        // Wire search callback from header to panel
        header->on_search_changed = [](const wchar_t* query, void* ud) {
            auto* panel = static_cast<CommitHistoryPanelWidget*>(ud);
            if (panel->on_search_changed) {
                panel->on_search_changed(panel, query, panel->search_user_data);
            }
        };
        header->search_user_data = this;

        widget_add_child(this, header);

        // Create scroll container
        scroll_container = arena.create<ScrollContainer>();
        scroll_container->width_mode = SizeMode::Fill;
        scroll_container->height_mode = SizeMode::Fill;
        scroll_container->flex = 1.0f;  // Take remaining space
        widget_add_child(this, scroll_container);

        // Create list widget
        list = arena.create<CommitHistoryListWidget>();
        list->init_pool(arena);
        list->width_mode = SizeMode::Fill;
        list->on_selection_changed = [](CommitHistoryListWidget* l, int idx, void* ud) {
            (void)l;
            CommitHistoryPanelWidget* panel = static_cast<CommitHistoryPanelWidget*>(ud);
            if (panel->on_selection_changed) {
                panel->on_selection_changed(panel, idx, panel->user_data);
            }
        };
        list->user_data = this;

        // Wire up scroll request callback for keyboard navigation
        list->on_scroll_request = [](CommitHistoryListWidget* l, float scroll_y, void* ud) {
            (void)l;
            CommitHistoryPanelWidget* panel = static_cast<CommitHistoryPanelWidget*>(ud);
            if (panel->scroll_container) {
                panel->scroll_container->scroll_y = scroll_y;
                panel->scroll_container->set_layout_dirty();
                panel->scroll_container->set_dirty();
            }
        };
        list->scroll_request_user_data = this;

        widget_add_child(scroll_container, list);
    }

    // Set the history to display
    void set_history(const GitHistory* h) {
        if (list) {
            list->set_history(h);
        }
        if (header) {
            header->set_commit_count(h ? h->commit_count : 0);
        }
        set_layout_dirty();
    }

    // Rebuild list from filtered indices
    void set_filtered_history(const int* filter_indices, size_t filter_count, size_t total_count) {
        if (list) {
            list->rebuild_from_filter(filter_indices, filter_count);
        }
        if (header) {
            header->set_filtered_count(filter_count, total_count);
        }
        set_layout_dirty();
    }

    // Clear filter and show all commits
    void clear_filter() {
        if (list) {
            list->rebuild_from_history();
        }
        if (header) {
            header->set_commit_count(list && list->history ? list->history->commit_count : 0);
        }
        set_layout_dirty();
    }

    // Clear search and filter
    void clear_search() {
        if (header) {
            header->clear_search();
        }
        clear_filter();
    }

    // Get current selection
    int get_selected_index() const {
        return list ? list->selected_index : -1;
    }

    // Set selection
    void set_selection(int index) {
        if (list) {
            list->set_selection(index);
        }
    }

    void measure(const LayoutConstraints& c) override {
        // Measure header
        if (header) {
            header->measure(c);
        }

        // Measure scroll container (will measure list)
        if (scroll_container) {
            LayoutConstraints scroll_c = c;
            scroll_c.max_height -= header ? header->preferred_height : 0;
            scroll_container->measure(scroll_c);
        }

        preferred_width = c.max_width;
        preferred_height = c.max_height;
    }

    void layout() override {
        float x = rect.x;
        float y = rect.y;
        float w = rect.width;
        float h = rect.height;

        // Layout header at top
        float header_h = CommitHistory::HEADER_HEIGHT;
        if (header) {
            header->rect.x = x;
            header->rect.y = y;
            header->rect.width = w;
            header->rect.height = header_h;
            header->layout();
        }

        // Layout scroll container below header
        if (scroll_container) {
            scroll_container->rect.x = x;
            scroll_container->rect.y = y + header_h;
            scroll_container->rect.width = w;
            scroll_container->rect.height = h - header_h;
            scroll_container->layout();
        }
    }

    void render(RenderContext& ctx) override {
        if (!(flags & WidgetFlags::Visible)) return;

        // Render header
        if (header) {
            header->render(ctx);
        }

        // Render scroll container (handles list rendering with clipping)
        if (scroll_container) {
            scroll_container->render(ctx);
        }
    }

    bool on_mouse_move(float x, float y) override {
        // Forward to appropriate child
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        // Check header first (for search box hover)
        if (header && header->rect.contains(abs_x, abs_y)) {
            float child_x = abs_x - header->rect.x;
            float child_y = abs_y - header->rect.y;
            return header->on_mouse_move(child_x, child_y);
        }

        if (scroll_container && scroll_container->rect.contains(abs_x, abs_y)) {
            float child_x = abs_x - scroll_container->rect.x;
            float child_y = abs_y - scroll_container->rect.y;
            return scroll_container->on_mouse_move(child_x, child_y);
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        // Check header first (for search box click)
        if (header && header->rect.contains(abs_x, abs_y)) {
            float child_x = abs_x - header->rect.x;
            float child_y = abs_y - header->rect.y;
            return header->on_mouse_down(child_x, child_y, button);
        }

        if (scroll_container && scroll_container->rect.contains(abs_x, abs_y)) {
            float child_x = abs_x - scroll_container->rect.x;
            float child_y = abs_y - scroll_container->rect.y;
            return scroll_container->on_mouse_down(child_x, child_y, button);
        }
        return false;
    }

    bool on_mouse_up(float x, float y, int button) override {
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        // Check header first (for search box)
        if (header && header->rect.contains(abs_x, abs_y)) {
            float child_x = abs_x - header->rect.x;
            float child_y = abs_y - header->rect.y;
            return header->on_mouse_up(child_x, child_y, button);
        }

        if (scroll_container && scroll_container->rect.contains(abs_x, abs_y)) {
            float child_x = abs_x - scroll_container->rect.x;
            float child_y = abs_y - scroll_container->rect.y;
            return scroll_container->on_mouse_up(child_x, child_y, button);
        }
        return false;
    }

    bool on_mouse_wheel(float x, float y, float delta) override {
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        if (scroll_container && scroll_container->rect.contains(abs_x, abs_y)) {
            float child_x = abs_x - scroll_container->rect.x;
            float child_y = abs_y - scroll_container->rect.y;
            return scroll_container->on_mouse_wheel(child_x, child_y, delta);
        }
        return false;
    }

    bool on_mouse_leave() override {
        if (list) {
            return list->on_mouse_leave();
        }
        return false;
    }

    TextInput* get_search_input() {
        return header ? header->search_input : nullptr;
    }
};
